import socket
import json

# Server configuration
SERVER_IP = '0.0.0.0'
SERVER_PORT = 12345

# Create a UDP socket
server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)

# Bind the socket to the server IP and port
server_socket.bind((SERVER_IP, SERVER_PORT))

def get_player_list():
    # Simulate player list for demonstration purposes
    players = [
        {"id": 1, "name": "Player 1", "score": 100},
        {"id": 2, "name": "Player 2", "score": 200},
        {"id": 3, "name": "Player 3", "score": 300}
    ]
    return json.dumps(players)

def get_game_state():
    # Simulate game state for demonstration purposes
    game_state = {
        "game_id": 1,
        "map_name": "Map 1",
        "players": [
            {"id": 1, "name": "Player 1", "score": 100},
            {"id": 2, "name": "Player 2", "score": 200}
        ]
    }
    return json.dumps(game_state)

def handle_status_query(data, address):
    try:
        query = json.loads(data.decode('utf-8'))
        if query.get("type") == "status":
            player_list = get_player_list()
            game_state = get_game_state()
            response = {"player_list": player_list, "game_state": game_state}
            server_socket.sendto(json.dumps(response).encode('utf-8'), address)
    except Exception as e:
        print(f"Error handling status query: {e}")

while True:
    data, address = server_socket.recvfrom(1024)
    handle_status_query(data, address)